INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (191, 4, '海思科医药集团股份有限公司', 1, '地址一：西藏自治区山南地区泽当镇三湘大道17号\n地址二：四川省成都市温江区海峡两岸科技产业开发园百利路137号', '2021-05-13 10:17:22', NULL, NULL, 24, 272, '成立于2000年，是一家集新药研发、生产制造、销售等业务于一体的多元化、专业化医药集团上市公司。公司的研发实力在化学制药行业中名列前茅，系肠外营养细分领域产品线最全的领军企业，也在肝病治疗、抑郁、抗感染等细分市场占据重要地位。公司拥有覆盖麻醉及镇痛、肠外营养、肿瘤止吐、肝病治疗、消化系统、神经系统、抗感染等多个细分领域的产品布局，现有49个品种多为国内首家或独家仿制，主要产品包括环泊酚注射液、复方氨基酸注射液（18AA-VII）、脂肪乳氨基酸（17）葡萄糖（12%）注射液、甲磺酸多拉司琼注射液、注射用甲泼');
