INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (292, 3, '沛嘉医疗科技（苏州）有限公司', 1, '江苏省苏州市吴中区苏州工业园区直属镇中田巷8号', '2023-01-30 11:14:11', NULL, NULL, 11, 113, '沛嘉医疗是全球医疗创新解决方案服务商，秉持“至善尽心，敬畏生命”的理念，致力于通过持续的创新，提供安全、有效和患者可及的产品和解决方案，减轻病患痛苦，提升病患生活质量，成为一家以患者为中心、具备原创精神及受人尊敬的全球化高科技医疗企业。公司成立于2012年，总部位于苏州。2020年5月在香港联合交易所主板上市，股票代码9996.HK。\n\n沛嘉医疗定位“创新为本，心脑同治”战略布局，专注于创新、研发及生产结构性心脏病和脑血管介入领域高端医疗器械，涵盖主动脉瓣、二尖瓣、三尖瓣及手术附件，脑血管介入出血类、缺血类、通路类产品。公司三代主动脉瓣系统全部获批国家药品监督管理局创新医疗器械。\n\n沛嘉医疗以全球视野引领创新发展，在美国、加拿大、法国等国家布局全球创新中心及研发中心，开展前沿技术研究和产品开发。在生物材料处理技术、精密生产能力、质量管理体系及专利组合等方面拥有独特的比较优势。公司在中国上海、苏州建设有符合GMP标准的高端医疗器械生产（研发）基地，产品已覆盖数千家医院。');
