INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (392, 2, '深圳豪石生物科技有限公司', 1, '广东省深圳市宝安区新桥街道黄埔社区洪田路155号创新智慧港2栋七层', '2023-01-31 11:42:08', NULL, NULL, 20, 235, '深圳豪石生物科技有限公司（以下简称“豪石生物”）是由 一批留美归国专业技术人员于2017年创建，2019年在深圳市宝安区创新智慧港2栋7层建成细胞库和符合国家GMP标准的细胞治疗产品的研 发、生产实验室。\n\n豪石生物专注细胞储存，细胞治疗，并开展免疫细胞治疗肿 瘤的研究、转化及临床应用。豪石生物已与国内外多个科研机构的专家、教授、学者合作，开展单靶点CAR-T、双靶点CAR-T、CTL等肿瘤 治疗技术的临床前期研究。\n\n豪石生物持续引进国内外生物医药领域专业人才，为客户提 供专业化的服务，为提升企业的国际竞争力奠定了基础。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (393, 4, '普华赛尔生物医疗科技有限公司', 1, '北京市东城区广渠家园8号楼普华赛尔大厦', '2023-01-31 11:48:47', NULL, NULL, 2, 36, NULL);
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (394, 4, '北京创立科创医药技术开发有限公司', 1, '北京市朝阳区北三环东路28号易亨大厦601室', '2023-01-31 11:58:18', NULL, NULL, 2, 36, NULL);
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (395, 2, '广东艾琳杉医疗咨询服务有限公司', 1, '广州市白云区鹤龙街尹边一街78号3楼303房', '2023-01-31 13:36:04', NULL, NULL, 20, 233, NULL);
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (396, 4, '北京门罗生物科技有限公司', 1, '北京市昌平区奇点中心', '2023-01-31 13:52:11', NULL, NULL, 2, 36, '北京门罗生物科技有限公司是在第三代基因编辑技术及iPSC干细胞技术研究转化成果上建立起来的新型免疫治疗及基因治疗企业。\n \n公司已成功开发了具有自主知识产权的高精准基因编辑技术平台及iPSC干细胞诱导分化技术平台，研发出多款通 用型细胞免疫治疗及基因治疗产品，可以为血液瘤和实体瘤提供可负担起的、更有效的治疗方案。\n \n公司已完成多款通用型细胞免疫治疗产品的临床前研发，产品已进入生产工艺开发及优化。同时目前正在选择合适的PI 和医院计划开展探索性研究者发起的临床研究(Investigator Initiated Trial, IIT)。');
