INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (398, NULL, '重庆希尔安药业有限公司', 1, '重庆市合川工业园区希尔安路168号', '2023-02-01 11:56:20', NULL, NULL, 23, 271, '致力于打造骨伤科、儿科、皮肤科等多条具有竞争优势的产品线。公司重点品种如小儿黄龙颗粒、金蝉止痒胶囊、麝香追风止痛膏、跌打七厘片等均为独家或专利产品');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (399, NULL, '陕西方舟制药有限公司', 1, '西安市高新技术开发区高新三路19号方舟国际', '2023-02-01 11:56:20', NULL, NULL, 28, 325, '成立于1999年，是一家集中药、化药、原料药研发、生产、销售于一体的现代化高科技制药企业。公司在“抗肿瘤、抗衰老”专业供应商战略的指引下，主导产品“阿瑞斯”、“复方斑蝥胶囊”、“丹栀逍遥胶囊”、“阿胶当归胶囊”均在市场占有率处于前列，在帮助众多患者解除病魔之苦的同时，也造就了企业的快速发展，成为制药领域的品牌企业。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (400, NULL, '湖南天地恒一医药有限公司', 1, '湖南长沙国家生物产业基地康天路', '2023-02-01 11:56:20', NULL, NULL, 19, 219, '化学原料药（含肿瘤药）、片剂（含肿瘤药）、胶囊剂（含肿瘤药）、小水针（含肿瘤药）、大输液（含肿瘤药）、无菌粉针（含肿瘤药）、冻干粉针（含肿瘤药）、肿瘤口服溶液和中药提取、颗粒剂、丸剂等生产线。');
