INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (721, NULL, '杭州多禧生物', 1, '浙江杭州市杭州经济技术开发区6号大街260 号中自科技园13栋', '2023-02-03 13:54:11', NULL, NULL, 12, 122, '于2012年12月31日创立。公司拥有自主知识产权的ADC药物平台涵盖：连接技术方面，拥有新型智能化连接子（包括定点偶联）共约50余种；小分子细胞毒性化合物方面，拥有5大类，共约101余种分子，涵盖抗微管蛋白（Tubulysin）、DNA小沟槽结合体（PBD）、DNA烷基化类(Duocarmycin)、RNA聚合酶抑制剂类(Amanitin)、拓扑酶抑制剂类(CPT)等；抗体工程方面，建立了完善的抗体构建和生产工艺。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (722, NULL, '中山珐玛斯医药科技有限公司', 1, '中山市火炬开发区广济西路1号之一厂房6楼', '2023-02-03 13:54:11', NULL, NULL, 20, 250, '从事药物候选物的药理、药物代谢及毒理的检验检测服务。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (723, NULL, '西安泰科迈医药科技股份有限公司', 1, '西安市高新技术开发区锦业路69号瞪羚谷C区1号创业研发园B座7楼', '2023-02-03 13:54:11', NULL, NULL, 28, 325, '成立于2011年，是一家专业从事药品研究和技术开发的高新技术企业。主营业务：抗肿瘤新药研发，化学原料药开发，化学仿制药研发，仿制药一致性评价技术服务，中药开发及技术服务，药物临床研究服务。多年来以药品研发为己任，以打造成国内一流的药物研发机构和专业的药品服务商为目标。在癌症、心脑血管、肠胃道、免疫力低下、神经系统等疾病领域，应用纳米递释技术、缓控释技术、逆向工程技术先后为100余家企业研发申报注册中药、化药仿制药、保健品等药品201多个。公司立足于化药原料药开发、仿制药开发、仿制药一致性评价、尤其是对缓控');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (724, NULL, '杭州百诚医药科技有限公司', 1, '杭州市滨江区东冠路611号金盛科技园8号楼3层', '2023-02-03 13:54:11', NULL, NULL, 12, 122, '公司业务涵盖药物发现、药学研究、临床研究、注册申请等药物研发主要环节，其中在药学研究和生物等效性试验（简称BE临床试验）研究服务上具有核心竞争优势。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (725, 2, '博瑞生物医药技术（苏州）有限公司', 1, '苏州工业园区星湖街218号纳米科技园C25栋', '2023-02-03 13:54:11', NULL, NULL, 11, 113, '暂时没有新产品的临床试验需求，21年底申报的治疗晚期实体肿瘤的一期临床还没结束。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (726, NULL, '博生吉医药科技有限公司', 1, '苏州工业园区星湖街218号生物纳米园B1-413', '2023-02-03 13:54:11', NULL, NULL, 11, 113, '2010年5月32日注册成立在苏州工业园区，可开展国际一流水平的细胞治疗新技术的研发，涵盖抗原结合域的开发、CAR结构的优化、CAR-T细胞的功能测试、直至体内药效试验的验证。拥有先进的CAR结构及功能验证平台、CAR-T细胞体内药效验证平台、Safeγ UCAR-γδT细胞药物开发平台、iPSC诱导的现货型细胞药物开发平台、以及NanoBa双特异抗体研发平台。\n\n公司专注于开发具有国际领先水平的突破性First-in-class和Best-in-class CAR-T细胞药物，已有多个细胞产品进入POC');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (727, NULL, '苏州沪云肿瘤研究中心股份有限公司', 1, '苏州工业园区华云路1号东坊产业园C区8号楼五楼', '2023-02-03 13:54:11', NULL, NULL, 2023-02-03 13:54:12, 578, '抗医疗技术的研发；的免疫治疗方法研究与开发；抗新药的技术开发、技术咨询及�杭康药业有限公司');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (736, NULL, '杭州澳医保灵药业有限公司', 1, '浙江省杭州市钱塘区23号大街669号', '2023-02-03 13:54:12', NULL, NULL, 12, 122, '由杭州保灵有限公司与澳大利亚澳医集团、新加坡爱美雅美容沙龙有限公司合资组建，建有原料药、药品、保健食品、食品生产等车间。保灵药业的主要产品有“保灵孕宝”口服液，药品有“保灵牌”蜂皇胎胶囊、国家二类新药依巴斯汀片、醋甲唑胺片，保健食品有蜂皇浆胶囊、蜂胶片、孕妇多维片(胶囊)、孕妇钙咀嚼片等。');
