INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1195, 2, '杭州糖吉医疗科技有限公司', 1, '中国 杭州 滨江区 滨安路688号 天和高科技园', '2023-03-06 14:04:52', NULL, NULL, 12, 122, '研发了多款面向肥胖症、2型糖尿病、非酒精性脂肪肝等代谢性疾病的医疗新技术。已有在研项目近10个，申报专利50余项，多款产品正在20余家知名医院开展不同阶段的临床试验');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1196, 2, '杭州尚健生物技术有限公司', 1, '北京市经济技术开发区生物医药园', '2023-03-09 15:41:20', NULL, NULL, 12, 122, '尚健生物始终坚持技术创新引领产品创新。创建以来，组建了一支拥有丰富抗体药物研发及产业化经验的专业团队，多名院士、国际级和国家级专家担纲科学顾问；以杭州为总部和产业化基地，同时在北京等地建立了国际领先的早期研发中心；与华东理工大学等知名科研院校开展深度合作；建立了国内领先的从抗体研发到规模化生产和临床转化的全流程技术体系，重点围绕肿瘤领域布局了一系列原创产品，申请国家及PCT专利100余项；首个1类新药SG001已进入注册Ⅱ期临床，SG301、SG404、SG12473、SG2501、SG1408等多个项目先后在国内外启动并开展临床研究；获汉康资本、国药中生、毅达资本、华睿投资、同创伟业、君川资本、浙商创投等机构多轮投资；与石药集团达成SG001项目联合开发协议；2020年3月，在区政府的支持下，尚健生物将中国生物技术股份有限公司引入滨江，成立合资公司——中生尚健生物医药（杭州）有限公司，进一步加快创新抗体药物产业化，促进区域生物医药产业快速发展');
