INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1270, 2, '武汉兰丁智能医学股份有限公司', 1, '湖北省武汉市东湖新技术开发区高新大道818号医疗器械园B7栋', '2023-04-21 15:13:03', NULL, NULL, 18, 205, '武汉兰丁智能医学股份有限公司（前身为武汉兰丁医学高科技有限公司）成立于2000年，总部及研发基地坐落在中国光谷生物城医疗器械园，是一家由海归博士孙小蓉及其团队共同创办的以人工智能大数据云诊断为技术核心的高新技术企业。兰丁的主要业务是用自动化、智能化、数字化、标准化、网络化、规模化细胞病理诊断技术服务于临床各类高发肿瘤的早期诊断。\n\n      兰丁构建了Al+大数据云宫颈癌筛查的智能化数字化远程化产业链，完成了人工智能宫颈癌细胞诊断机器人“Landing”的自主研发及产业化，在全世界首创大规模宫颈癌筛查专家共享、数据共享和资源共享的云诊断平台');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1271, 2, '苏州玉森新药', 1, '苏州工业园区星湖街218号生物纳米科技园C30楼', '2023-04-21 17:07:41', NULL, NULL, 11, 113, '公司还是以1.1类新药为主，\n每年立项产品临床都是自己做的，公司自己本身也对外做CRO和CDMO的业务');
