INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1275, 2, '苏州般若生物科技有限公司', 1, '苏州工业园区星湖街218号生物纳米园A2楼308', '2023-04-23 16:49:48', NULL, NULL, 11, 113, '公司自主开发的实体瘤高异质性，目前已开发出溶瘤病毒候选药，临床还需要一段时间。\n创始人是留美博士回国，有产业基金投资。');
