INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1279, 2, '北京东方运嘉科技发展有限公司', 1, '北京朝阳区惠新东街甲2号住总地产大厦801', '2023-04-24 14:36:57', NULL, NULL, 2, 36, '北京东方运嘉科技发展有限公司（以下简称“东方运嘉”）成立于1998年3月11日，是一家专注医药业务领域的技术研发公司, 业务围绕中医药领域，以“中药新药研发”为主体，全面深耕验方处方筛选论证、中医药技术开发、医学学术支持等技术/服务输出事务性工作。\n方运嘉是国家高新技术企业、中关村高新技术企业，拥有多项国家发明专利。根据自主专利研发的“苏黄止咳胶囊”是北京市自主创新产品，是国内首个治疗咳嗽变异性哮喘和感冒后咳嗽（感染后咳嗽）的中成药，该产品的推出填补了市场空白，并获得了医药界同仁和患者的一致认可和好评，累计实现销售额超百亿元，为企业获得大量奖项及荣誉。\n多年耕耘，东方运嘉已建立起完善的中药新药研发体系，并布局呼吸疾病、儿童疾病、成人慢病/常见病等多个系列研发产品管线。');
