INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1405, 2, '同宜医药', 1, '工业园区星湖街218号C36楼201', '2023-12-08 17:21:14', NULL, NULL, 11, 113, '拜访了他们的临床PM叫 毛立明。2015年曾经在兴德通工作过，所以也比较坦诚。\n他们同宜自己的项目，筛选CRO是必须要在美国有团队才可以，\n基本上都是中美双报。一直有合作的CRO是泰格。');
