INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1420, 2, '苏州信诺维医药', 10, '苏州工业园区桑田街218号生物产业园二期22号楼', '2024-01-03 16:16:03', NULL, NULL, 11, 113, '。基于自主创新的靶向治疗、抗感染和PROTAC三大技术平台，信诺维已形成BLI抑制剂、EZH2抑制剂、hURAT1抑制剂以及新一代ADC等创新药管线，覆盖肿瘤、抗感染和代谢等疾病领域。目前公司已有多个产品处于临床研发阶段\n');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1421, 2, '浙江特瑞思药业股份有限公司', 1, '浙江省湖州市南太湖生物医药产业园环山路798号', '2024-01-05 14:21:14', NULL, NULL, 12, 126, '专注于抗体类药物的研发、中试放大和商业化，产品管线涵盖创新抗体偶联药物（ADC）、生物类似药及改良型单抗药物等，为肿瘤的治疗提供安全、有效、可及的临床解决方案，以满足大量尚未被满足的临床需求。目前已拥有8个高价值产品管线，已获得3项“重大新药创制”，4个临床批件，21项专利申请，治疗领域涵盖多种恶性肿瘤（淋巴瘤，肺癌，结直肠癌，肾癌，胰腺癌，肝癌和乳腺癌等）。');
