INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1439, 4, '上海鼎辉医药有限公司', 1, '上海市闵�', '2024-09-07 23:15:58', NULL, NULL, 10, 108, '恒润达生是一家专注于突破性免疫细胞治疗药物研发与生产的创新生物医药公司，主要聚焦恶性血液病和实体肿瘤等治疗领域。公司以CAR-T产品自主研发为先导，同步布局CAR-NK等国际前沿技术，形成了从早期研发到成熟临床试验阶段的产品管线布局，兼具梯次丰富性和技术前瞻性，是拥有5个1类创新型生物制品（CAR-T细胞治疗产品）注册临床批件且同时推进的创新生物医药企业。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1492, 2, '北京鼎成肽源生物技术有限公司', 1, '北京市昌平区双营西路86号院4号楼1至5层1单元101', '2024-09-07 23:26:22', NULL, NULL, 2, 36, '北京鼎成肽源生物技术有限公司（简称“鼎成肽源”）成立于2014年3月，是以免疫细胞治疗产品研发和成果转化为主的“双高新”技术企业、北京市“专精特新” 中小企业、中关村金种子企业，北京市级企业科研机构，设立免疫学博士后科研工作站。围绕靶点发现、序列发现、序列评价和功能增强等环节，搭建独立自主的核心技术平台，进行TCR-T、TCR蛋白药和CAR-T细胞治疗产品的开发。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1493, 2, '北京卡替医疗', 1, '北京市北京经济技术开发区科创六街88号院6号楼2单元501室', '2024-09-07 23:41:07', NULL, NULL, 2, 36, '北京卡替(Chineo)医疗公司的核心研发团队由行业里的顶级科学家和临床研究专家组成，已在TIL/新抗原等创新免疫细胞治疗技术上深耕多年。卡替医疗自主研发的“超强型TIL”免疫细胞治疗技术，是目前处于国际最前沿的TIL和CAR-T等技术基础上的“青出于蓝”的重大升级。目前卡替医疗公司的“超强型TIL”细胞治疗产品已完成IND申报');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1494, 2, '深圳莱芒生物', 1, '深圳市福田区福保街道福保社区海红道1号综合信兴一期三层320-A、320-D', '2024-09-07 23:49:09', NULL, NULL, 20, 235, '深圳莱芒生物科技有限公司是一家处于临床阶段的免疫代谢治疗药物研发公司，由瑞士洛桑联邦理工学院唐力教授团队联合晶泰科技共同创立。基于免疫代谢重编程+前沿人工智能的创新技术，公司专注于研发、生产和商业化新型肿瘤免疫治疗药物。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1495, 2, '沃昕生物科技（深圳）有限公司', 1, '深圳市宝安区新安街道兴东社区67区大仟工业厂区宿舍105、106', '2024-09-07 23:57:02', NULL, NULL, 20, 235, '沃昕生物科技（深圳）有限公司（简称“沃昕生物”）成立于2016年，是一家致力于肿瘤免疫治疗技术研发及技术服务、肿瘤治疗中心投资与管理的技术企业。沃昕生物拥有先进的研发平台、严格的细胞质量管理标准、高效的市场开发团队和完善的运营管理体系。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1496, 2, '重庆精准生物技术有限公司', 1, '重庆市九龙坡区含谷镇含兴路38号', '2024-09-08 00:05:00', NULL, NULL, 23, 271, '公司作为硬核科技创新型企业，掌握细胞领域关键技术，拥有多项授权发明专利，并在发达国家和地区进行了专利布局；公司实施推进了白血病、淋巴瘤、骨髓瘤、肠胃癌、肺癌、肝癌、乳腺癌、胰腺癌等10余项CAR-T研发管线，获得四个CAR-T细胞一类生物新药、九项适应症的默示许可，国内首个自主研发治疗儿童白血病的pCAR-19B细胞自体回输制剂（普基仑赛注射液）获准纳入“突破性治疗品种”、“优先审评品种”，2024年提交上市申请并于7月获国家药监局受理。同时，公司实现了CAR-T治疗肾癌、结直肠癌、胃癌等实体瘤技术的突破，相关产品获批注册临床，正积极推进药物注册临床。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1497, 2, '北京循生生物医学', 1, '北京市大兴区天华大街33号院5号楼三层301', '2024-09-08 00:11:38', NULL, NULL, 2, 36, '循生医学是一家以肿瘤免疫治疗研究为核心的创新生物医药公司，致力于研发新型个体化肿瘤免疫治疗产品。公司和国内外科学家携手，瞄准最前沿的免疫治疗技术，为全球病患提供更为安全、有效的创新药物和治疗方案。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1498, 2, '厦门诺康得生物科技有限公司', 1, '厦门市翔安区民安街道莲亭路811号301单元-3', '2024-09-08 00:19:05', NULL, NULL, 14, 151, '厦门诺康得生物科技有限公司是国际领先的基于糖化学生物学（cabonhydrate biochemistry）的新药研发公司。糖化学生物学在体内免疫中发挥重要作用。诺康得和厦门大学、美国密歇根州立大学等深入合作，设立海内外研发中心。相关技术处于国际一流水平。诺康得在巨噬细胞、NK细胞新型免疫检查点抑制剂、基于化学法而不是基因、病毒方法的细胞治疗（CECT）、糖基化乳腺癌癌症疫苗等领域均取得了卓越的成果。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1499, 2, '英百瑞（杭州）', 1, '浙江省杭州市滨江区长河街道长江路365号32幢101室', '2024-09-08 00:22:29', NULL, NULL, 12, 122, '英百瑞成立于2014年，从事肿瘤和免疫类疾病的治疗，2016年专注于创新型通用现货CAR-NK细胞疗法的开发，通过其原创的技术平台，研发出一系列细胞和抗体药物，致力于解决临床未满足的疾病，多个产品管线正在同步推向临床。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1500, 2, '上海精缮生物科技有限责任公司', 1, '上海市虹口区中山北一路1111号1号楼1层101室', '2024-09-08 00:28:39', NULL, NULL, 10, 108, '上海精缮生物科技有限责任公司（“精缮科技”）自主研发的细胞和基因治疗产品GC101（“该产品”）的临床试验申请于近日获国家药品监督管理局批准。该产品为1类治疗用生物制品（创新型生物制品），可用于隐性营养不良型大疱性表皮松解症。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1501, 2, '深圳市先康达生命科学有限公司', 1, '深圳市坪山区坑梓街道金沙社区青兰三路24号威尔德工业园厂房1栋503', '2024-09-08 00:34:08', NULL, NULL, 20, 235, '深圳先康达生命科学有限公司（简称“先康达生命”）成立于2020年3月，是一家专注于实体瘤细胞免疫疗法研究及产业化的高新技术企业，布局了2大主流细胞治疗，T（CAR-T，CAR-iT）和NK（PANK，CAR-NK）。公司开发了3个具有自主知识产权的技术平台：Trans-CAR、Boost-CAR，R-Star，以及2大针对NK的工艺平台：hNK.LV和FCF-NK，在多家三甲医院开展了实体瘤CAR-T及PANK的临床研究，相关数据已初步显示出可控的安全性和良好的临床疗效。');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1502, 2, '星奕昂（上海）生物', 1, '中国(上海)自由贸易试验区巴圣路160号7幢5单元3层', '2024-09-08 00:37:34', NULL, NULL, 10, 108, '星奕昂是一家专注于iPSC衍生的CAR-NK技术开发新一代免疫细胞产品的创新型生物医药公司，由原复星凯特首任CEO王立群博士创立。公司在自主创新研发的同时，积极与全球先进的机构合作，为全球患者提供安全有效的治疗药物。');
