INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1507, 4, '安徽省先锋制药', 1, '合肥高新技术产业开发区红枫路35号', '2024-11-02 13:49:41', NULL, NULL, 13, 133, '公司研发中心现有专职研发人员近40人，其中博士3人，硕士6人，开发产品主要涵盖心脑血管、精神类、呼吸类、消化类、抗肿瘤、抗感染用药、大健康类等多个治疗领域。目前项目主要为化药3类、4类，涉及抗菌药、激素药\n');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1508, 4, '珍视明（江西）药业股份有限公司', 1, '江西省抚州市临川区迎宾大道218号', '2024-11-02 13:54:05', NULL, NULL, 15, 168, '珍视明公司在研发上坚持自主研发， 拥有超过 70+ 项专利。 珍视明拥有 70+ 产品，拥有滴眼液为主的药品批文 51 个,国家医保品种。珍视明滴眼液、蒸汽眼罩、眼贴、洗眼液等产品，均占据品类市场领先地位。\n');
