INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1510, 2, '上海贝斯昂科', 1, '中国（上海）自由贸易试验区金苏路200号、冀桥路700号23幢1楼', '2024-12-03 16:23:02', NULL, NULL, 10, 108, '成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力，成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1511, 2, '上海贝斯昂科', 1, '中国（上海）自由贸易试验区金苏路200号、冀桥路700号23幢1楼', '2024-12-03 16:23:02', NULL, NULL, 10, 108, '成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力，成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1512, 2, '浙江泉生生物', 1, '浙江省湖州市安吉县递铺街道越都中路浙北生命健康小微园6号楼（自主申报）', '2024-12-03 16:35:36', NULL, NULL, 12, 126, '浙江泉生生物科技有限公司（曾用名：上海泉生生物科技有限公司，简称“泉生生物”）由中组部“千人计划”专家齐念民教授于2016年创办，泉生生物严格依照国家干细胞相关法规政策要求，致力于干细胞制剂临床前研究/实验、人体临床研究/试验、IND/NDA注册申报及产业化');
INSERT INTO contract_products (product_id, category_id, name, company_id, address, created_at, fax, login_name, province_id, city_id, remark) VALUES (1513, 2, '深圳市茵冠生物科技有限公司', 1, '深圳市茵冠生物科技有限公司', '2024-12-03 17:31:50', NULL, NULL, 20, 235, '深圳市茵冠生物科技有限公司是一家致力于细胞与基因治疗领域，聚焦于干细胞创新药物及联合疗法，集研究、开发、转化及应用的高科技企业，公司提供细胞治疗及基因治疗全产业链产业化服务，以干细胞临床研究与转化应用、癌症的细胞生物治疗、基因治疗、细胞储存、健康管理及公共技术服务平台等为主要业务，致力于将茵冠生物打造成集技术与服务为一体的国内顶尖、国际一流医疗健康服务集团。');
